  function classifyLog(log, counters) { const text = String(log.text || log.message || log.title || ''); if (BUY_LOG_IDS.includes(Number(log.logTypeId))) { counters.buyIdMatches += 1; return 'buy'; } if (SELL_LOG_IDS.includes(Number(log.logTypeId))) { counters.sellIdMatches += 1; return 'sell'; } if (parseBuyText(text)) { counters.textBuyMatches += 1; return 'buy'; } if (parseSaleText(text)) { counters.textSellMatches += 1; return 'sell'; } return 'other'; }
