    async function userLogs(options = {}) { const params = {}; if (options.from) params.from = dateToTimestamp(options.from, false); if (options.to) params.to = dateToTimestamp(options.to, true); const started = nowMs(); const result = await request('log', params); const logs = result.ok ? normalizeLogs(result.data) : []; const counters = { buyIdMatches: 0, sellIdMatches: 0, textBuyMatches: 0, textSellMatches: 0 }; logs.forEach((log) => classifyLog(log, counters)); const debug = { ...(result.debug || {}), rawLogsReturned: result.ok ? rawLogCount(result.data) : 0, normalizedLogs: logs.length, sampleRawKeys: result.ok ? sampleRawKeys(result.data) : [], buyIdMatches: counters.buyIdMatches, sellIdMatches: counters.sellIdMatches, textBuyMatches: counters.textBuyMatches, textSellMatches: counters.textSellMatches, firstSanitizedLogs: logs.slice(0, 5).map(sanitizeLog), timings: { requestAndNormalizeMs: nowMs() - started } }; return { ...result, logs, debug }; }
