  function finishDebug(summary, totalStarted, saveStarted) { return { ...(summary.debug || {}), appVersion: config.version, buyLogIds: BUY_LOG_IDS, sellLogIds: SELL_LOG_IDS, diagnosticMessage: summary.diagnosticMessage, lastError: (summary.errors || []).join(' '), firstSanitizedLogs: (summary.debug.firstSanitizedLogs || []).slice(0, 5), timings: { ...(summary.debug.timings || {}), saveMs: Math.max(0, nowMs() - saveStarted), totalMs: Math.max(0, nowMs() - totalStarted) } }; }
