  function injectStyles() { if (typeof GM_addStyle === 'function') { GM_addStyle(css); return; } const style = document.createElement('style'); style.textContent = css; document.head.appendChild(style); }
  function root() { let element = document.getElementById(config.rootId); if (!element) { element = document.createElement('section'); element.id = config.rootId; document.body.appendChild(element); } return element; }
