  function dashboard(data) { const s = stats(data); const p = portfolio(data); const apiNotice = data.settings.apiEnabled && !data.settings.logImportLastRunAt ? `<p class="ftp-preview">API connected. Run log import to automatically add purchases and sales.</p>` : ''; return `<section class="ftp-grid">${stat('Open investment', money(s.totalInvestment))}${stat('Lifetime profit', money(s.lifetimeProfit))}${stat('Trades', s.totalTrades)}${stat('Open items', p.length)}</section>${apiNotice}${card('Recent activity', `<p>${data.sales.length ? `Last sale: ${escapeHtml(data.sales[0].itemName)} for ${money(data.sales[0].totalSellPrice)}` : 'No sales recorded yet.'}</p>`)}`; }
  function calculator(data) { return card('Record Sale', `<form data-sale-form><label class="ftp-field"><span>Item name</span><input class="ftp-input" name="itemName" required></label><div class="ftp-grid"><label class="ftp-field"><span>Quantity</span><input class="ftp-input" name="quantity" type="number" min="1" value="1" required></label><label class="ftp-field"><span>Sell price each</span><input class="ftp-input" name="sellPrice" type="number" min="0" step="1" required></label></div><div class="ftp-grid"><label class="ftp-field"><span>Fees optional</span><input class="ftp-input" name="fees" type="number" min="0" step="1"></label><label class="ftp-field"><span>Manual buy price for unmatched quantity</span><input class="ftp-input" name="buyPrice" type="number" min="0" step="1"></label></div><label class="ftp-field"><span><input type="checkbox" name="manualBuyCostOverride"> Use manual buy cost for unmatched quantity</span></label><label class="ftp-field"><span>Notes</span><input class="ftp-input" name="notes"></label><div class="ftp-preview" data-sale-preview></div><div class="ftp-actions"><button class="ftp-primary" type="submit">Save sale</button></div></form>`); }
  function purchases(data) { const items = data.purchaseLots.filter((lot) => getRemaining(lot) > 0); return `${card('Add Purchase', `<form data-purchase-form><label class="ftp-field"><span>Item name</span><input class="ftp-input" name="itemName" required></label><div class="ftp-grid"><label class="ftp-field"><span>Quantity</span><input class="ftp-input" name="quantity" type="number" min="1" value="1" required></label><label class="ftp-field"><span>Buy price each</span><input class="ftp-input" name="buyPrice" type="number" min="0" step="1" required></label></div><label class="ftp-field"><span>Notes</span><input class="ftp-input" name="notes"></label><div class="ftp-actions"><button class="ftp-primary" type="submit">Add purchase</button></div></form>`)}${card('Open Purchases', items.length ? `<ul class="ftp-list">${items.map((lot) => row(`<strong>${escapeHtml(lot.itemName)}</strong><br><small>${getRemaining(lot)} left of ${lot.quantity} at ${money(lot.unitBuyPrice)}</small>`, `<button class="ftp-button" data-sell-lot="${escapeHtml(lot.id)}">Sell</button><button class="ftp-danger" data-delete-lot="${escapeHtml(lot.id)}">Delete</button>`)).join('')}</ul>` : '<p>No open purchases yet.</p>')}`; }
