  function bindShell(host, win) { const title = win.querySelector('[data-toggle]'); title.addEventListener('click', () => { const compact = win.dataset.mode === 'compact'; win.dataset.mode = compact ? 'expanded' : 'compact'; title.textContent = compact ? config.appName : 'FT'; saveWindowState(win); }); win.querySelector('[data-minimize]').addEventListener('click', () => { win.dataset.mode = 'compact'; title.textContent = 'FT'; saveWindowState(win); }); win.querySelector('[data-close]').addEventListener('click', () => { host.remove(); }); let drag = null; win.querySelector('[data-drag]').addEventListener('pointerdown', (event) => { if (event.target.closest('button')) return; const rect = host.getBoundingClientRect(); drag = { x: event.clientX - rect.left, y: event.clientY - rect.top }; host.style.left = `${rect.left}px`; host.style.top = `${rect.top}px`; host.style.right = 'auto'; event.currentTarget.setPointerCapture(event.pointerId); }); win.querySelector('[data-drag]').addEventListener('pointermove', (event) => { if (!drag) return; host.style.left = `${Math.max(8, event.clientX - drag.x)}px`; host.style.top = `${Math.max(8, event.clientY - drag.y)}px`; }); win.querySelector('[data-drag]').addEventListener('pointerup', (event) => { if (!drag) return; drag = null; event.currentTarget.releasePointerCapture(event.pointerId); saveWindowState(win); }); let resize = null; win.querySelector('[data-resize]').addEventListener('pointerdown', (event) => { if (win.dataset.mode === 'compact') return; const rect = win.getBoundingClientRect(); resize = { x: event.clientX, y: event.clientY, width: rect.width, height: rect.height }; event.currentTarget.setPointerCapture(event.pointerId); }); win.querySelector('[data-resize]').addEventListener('pointermove', (event) => { if (!resize) return; win.style.width = `${Math.max(320, resize.width + event.clientX - resize.x)}px`; win.style.height = `${Math.max(360, resize.height + event.clientY - resize.y)}px`; }); win.querySelector('[data-resize]').addEventListener('pointerup', (event) => { if (!resize) return; resize = null; event.currentTarget.releasePointerCapture(event.pointerId); saveWindowState(win); }); on('notify', ({ title, message }) => { const toast = document.createElement('section'); toast.className = 'ftp-toast'; toast.innerHTML = `<strong>${escapeHtml(title || 'Flip Tracker Pro')}</strong>${message ? `<span>${escapeHtml(message)}</span>` : ''}`; host.querySelector('[data-toasts]').appendChild(toast); setTimeout(() => toast.remove(), 3200); }); }

